import React, { useState, useEffect, useCallback } from 'react';
import './Calculator.css';

const CurrencyConverter = () => {
  const [inputs, setInputs] = useState({
    amount: '',
    fromCurrency: 'USD',
    toCurrency: 'INR'
  });
  const [result, setResult] = useState('');
  const [rate, setRate] = useState(0);
  const [suggestion, setSuggestion] = useState('');
  const [loading, setLoading] = useState(false);

  const fetchRate = useCallback(async () => {
    try {
      const response = await fetch(`https://api.exchangerate-api.com/v4/latest/${inputs.fromCurrency}`);
      const data = await response.json();
      setRate(data.rates[inputs.toCurrency]);
    } catch (error) {
      console.error('Error fetching rate:', error);
    }
  }, [inputs.fromCurrency, inputs.toCurrency]);

  useEffect(() => {
    const saved = localStorage.getItem('currencyInputs');
    if (saved) {
      setInputs(JSON.parse(saved));
    }
    fetchRate();
  }, [fetchRate]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setInputs({ ...inputs, [name]: value });
  };

  const convert = () => {
    setLoading(true);
    setTimeout(() => {
      const converted = parseFloat(inputs.amount) * rate;
      setResult(converted.toFixed(2));

      // AI Suggestion
      if (converted > 10000) {
        setSuggestion('💰 Large amount conversion. Ensure secure transaction.');
      } else {
        setSuggestion('✅ Conversion completed.');
      }

      localStorage.setItem('currencyInputs', JSON.stringify(inputs));
      setLoading(false);
    }, 500);
  };

  const updateRate = () => {
    fetchRate();
  };

  const reset = () => {
    setInputs({
      amount: '',
      fromCurrency: 'USD',
      toCurrency: 'INR'
    });
    setResult('');
    setSuggestion('');
    localStorage.removeItem('currencyInputs');
  };

  const generateReport = () => {
    alert(`Currency Conversion Report:\n${inputs.amount} ${inputs.fromCurrency} = ${result} ${inputs.toCurrency}\nRate: ${rate}`);
  };

  return (
    <div className="calculator">
      <h2>Currency Converter</h2>
      <div className="inputs">
        <label>Amount</label>
        <input type="number" name="amount" value={inputs.amount} onChange={handleInputChange} />

        <label>From Currency</label>
        <select name="fromCurrency" value={inputs.fromCurrency} onChange={handleInputChange}>
          {currencies.map(c => <option key={c} value={c}>{c}</option>)}
        </select>

        <label>To Currency</label>
        <select name="toCurrency" value={inputs.toCurrency} onChange={handleInputChange}>
          {currencies.map(c => <option key={c} value={c}>{c}</option>)}
        </select>

        <p>Exchange Rate: 1 {inputs.fromCurrency} = {rate} {inputs.toCurrency}</p>
      </div>
      <div className="buttons">
        <button onClick={convert} disabled={loading}>Convert</button>
        <button onClick={updateRate}>Update Rate</button>
        <button onClick={reset}>Reset</button>
        <button onClick={generateReport} disabled={!result}>Generate Report</button>
      </div>
      {loading && <div className="loading">Converting...</div>}
      {result && (
        <div className="results">
          <h3>Result</h3>
          <p>{inputs.amount} {inputs.fromCurrency} = {result} {inputs.toCurrency}</p>
        </div>
      )}
      {suggestion && (
        <div className="suggestion">
          <p>{suggestion}</p>
        </div>
      )}
    </div>
  );
};

export default CurrencyConverter;
